-- Variant: Year-Round Outdoor - 12w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    12,
    'Year-Round Outdoor - 12w 4x/wk',
    'seasonal',
    4,
    60,
    ARRAY['Improve overall fitness', 'Build strength and endurance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Year-Round Outdoor'
ON CONFLICT DO NOTHING;

