  AND pv.sessions_per_week = 4
ON CONFLICT DO NOTHING;

-- Variant: Year-Round Outdoor - 16w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    16,
    'Year-Round Outdoor - 16w 5x/wk',
    'seasonal',
    5,
    60,
    ARRAY['Improve overall fitness', 'Build strength and endurance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Year-Round Outdoor'
ON CONFLICT DO NOTHING;

